const { expect } = require("chai");
const { ethers } = require("hardhat");

describe("DocumentVault", function () {
  let DocumentVault;
  let documentVault;
  let owner;
  let user1;
  let user2;
  let authority;

  beforeEach(async function () {
    [owner, user1, user2, authority] = await ethers.getSigners();

    DocumentVault = await ethers.getContractFactory("DocumentVault");
    documentVault = await DocumentVault.deploy();

    await documentVault.waitForDeployment();
  });

  describe("Document Storage", function () {
    it("Should store a document and emit event", async function () {
      const ipfsHash = "QmT5NvUtoM5nWFfrQdVrFtvGfKFmG7AHE8P34isapyhCxX";
      const docHash = ethers.keccak256(ethers.toUtf8Bytes("test-document"));

      await expect(
        documentVault.connect(user1).storeDocument(
          ipfsHash,
          docHash,
          "Property Deed",
          "Property ownership document"
        )
      )
        .to.emit(documentVault, "DocumentStored")
        .withArgs(docHash, user1.address, ipfsHash, await ethers.provider.getBlock('latest').then(b => b.timestamp) + 1, "Property Deed");
    });

    it("Should prevent duplicate document storage", async function () {
      const ipfsHash = "QmTest123";
      const docHash = ethers.keccak256(ethers.toUtf8Bytes("test-doc"));

      await documentVault.connect(user1).storeDocument(
        ipfsHash,
        docHash,
        "Affidavit",
        "Test affidavit"
      );

      await expect(
        documentVault.connect(user1).storeDocument(
          ipfsHash,
          docHash,
          "Affidavit",
          "Test affidavit"
        )
      ).to.be.revertedWith("Document already exists");
    });
  });

  describe("Document Verification", function () {
    let testDocHash;

    beforeEach(async function () {
      const ipfsHash = "QmTest456";
      testDocHash = ethers.keccak256(ethers.toUtf8Bytes("verification-test"));
      await documentVault.connect(user1).storeDocument(
        ipfsHash,
        testDocHash,
        "Certificate",
        "Test certificate"
      );
    });

    it("Should verify valid document", async function () {
      const isValid = await documentVault.connect(user1).verifyDocument(testDocHash);
      expect(isValid).to.be.true;
    });

    it("Should return false for non-existent document", async function () {
      const fakeHash = ethers.keccak256(ethers.toUtf8Bytes("fake"));
      await expect(
        documentVault.verifyDocument(fakeHash)
      ).to.be.revertedWith("Document not found");
    });
  });

  describe("Access Control", function () {
    let testDocHash;

    beforeEach(async function () {
      const ipfsHash = "QmAccessTest";
      testDocHash = ethers.keccak256(ethers.toUtf8Bytes("access-test"));
      await documentVault.connect(user1).storeDocument(
        ipfsHash,
        testDocHash,
        "Legal",
        "Access test document"
      );
    });

    it("Should grant access to another user", async function () {
      const duration = 86400; // 1 day
      await expect(
        documentVault.connect(user1).grantAccess(testDocHash, user2.address, duration)
      )
        .to.emit(documentVault, "AccessGranted")
        .withArgs(testDocHash, user2.address, (await ethers.provider.getBlock('latest').then(b => b.timestamp)) + 1 + duration);

      const hasAccess = await documentVault.hasAccess(testDocHash, user2.address);
      expect(hasAccess).to.be.true;
    });

    it("Should revoke access", async function () {
      await documentVault.connect(user1).grantAccess(testDocHash, user2.address, 86400);
      await documentVault.connect(user1).revokeAccess(testDocHash, user2.address);

      const hasAccess = await documentVault.hasAccess(testDocHash, user2.address);
      expect(hasAccess).to.be.false;
    });

    it("Should allow owner to revoke document", async function () {
      await documentVault.connect(user1).revokeDocument(testDocHash);

      const isValid = await documentVault.connect(user1).verifyDocument(testDocHash);
      expect(isValid).to.be.false;
    });
  });

  describe("Roles", function () {
    it("Should assign authority role", async function () {
      await documentVault.connect(owner).addAuthority(authority.address);
      const hasRole = await documentVault.hasRole(
        "0x9f2df0fed2c77648de5860a4cc508cd0818c85b8e8cf58259f93a60380437173", // AUTHORITY_ROLE hash
        authority.address
      );
      expect(hasRole).to.be.true;
    });
  });
});
